import{_ as a,o as i,c as o,a2 as e}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"LoRA 入门","description":"","frontmatter":{},"headers":[],"relativePath":"lora/basics.md","filePath":"lora/basics.md","lastUpdated":1782223980000}'),r={name:"lora/basics.md"};function t(L,l,s,A,R,n){return i(),o("div",null,[...l[0]||(l[0]=[e('<h1 id="lora-入门" tabindex="-1">LoRA 入门 <a class="header-anchor" href="#lora-入门" aria-label="Permalink to &quot;LoRA 入门&quot;">​</a></h1><p>一句话：LoRA 是挂在底模上的小型附加模型，用来增强某个角色、画风、服装、姿势或概念。</p><h2 id="lora-能做什么" tabindex="-1">LoRA 能做什么 <a class="header-anchor" href="#lora-能做什么" aria-label="Permalink to &quot;LoRA 能做什么&quot;">​</a></h2><p>常见 LoRA 类型：</p><ul><li>角色 LoRA：让模型画某个固定人物或原创角色。</li><li>画风 LoRA：让画面接近某种绘画、动画或设计风格。</li><li>服装 LoRA：增加特定衣服、制服、盔甲或饰品。</li><li>姿势 LoRA：强化某类动作或构图。</li><li>细节 LoRA：增强质感、线条、手部或画面细节。</li><li>概念 LoRA：学习某个物体、场景、材质或设计语言。</li></ul><h2 id="lora-为什么不能乱用" tabindex="-1">LoRA 为什么不能乱用 <a class="header-anchor" href="#lora-为什么不能乱用" aria-label="Permalink to &quot;LoRA 为什么不能乱用&quot;">​</a></h2><p>LoRA 是在某个底模生态上训练出来的。它学到的是“如何修改这个底模内部的某些权重方向”。</p><p>因此：</p><ul><li>SD1.5 LoRA 通常不适合 SDXL。</li><li>SDXL LoRA 通常不适合 FLUX。</li><li>Pony LoRA 优先给 Pony 系模型。</li><li>FLUX.1 LoRA 不要默认给 FLUX.2。</li><li>Z-Image LoRA 优先给 Z-Image 系模型。</li></ul><h2 id="权重怎么调" tabindex="-1">权重怎么调 <a class="header-anchor" href="#权重怎么调" aria-label="Permalink to &quot;权重怎么调&quot;">​</a></h2><p>LoRA 权重表示它对底模影响的强度。</p><p>常见起步范围：</p><ul><li>角色 LoRA：0.6 到 0.9。</li><li>画风 LoRA：0.3 到 0.7。</li><li>细节 LoRA：0.2 到 0.5。</li><li>多个 LoRA 叠加：每个都适当降低。</li></ul><p>如果权重太高，可能出现画面发脏、人体崩坏、风格过强、脸型固定、背景失控等问题。</p><h2 id="多个-lora-怎么叠加" tabindex="-1">多个 LoRA 怎么叠加 <a class="header-anchor" href="#多个-lora-怎么叠加" aria-label="Permalink to &quot;多个 LoRA 怎么叠加&quot;">​</a></h2><p>建议从简单开始：</p><ol><li>先只开一个 LoRA，确认它有效。</li><li>固定 seed。</li><li>再加第二个 LoRA。</li><li>每次只改一个权重。</li><li>记录哪个 LoRA 负责哪个效果。</li></ol><p>常见组合：</p><ul><li>角色 LoRA + 画风 LoRA。</li><li>角色 LoRA + 服装 LoRA。</li><li>画风 LoRA + 细节 LoRA。</li></ul><p>不要一开始就叠五六个 LoRA。出问题后很难判断是谁造成的。</p><h2 id="下载-lora-前看什么" tabindex="-1">下载 LoRA 前看什么 <a class="header-anchor" href="#下载-lora-前看什么" aria-label="Permalink to &quot;下载 LoRA 前看什么&quot;">​</a></h2><p>重点看：</p><ul><li>Base model：是否匹配你的底模。</li><li>Trigger words：需要写哪些触发词。</li><li>Recommended weight：作者推荐权重。</li><li>Example prompts：示例提示词。</li><li>License：能否公开发布或商用。</li><li>评论区：是否有版本兼容问题。</li></ul><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><ul><li>只看预览图，不看 base model。</li><li>把 LoRA 当成完整模型。LoRA 必须配底模。</li><li>权重越高越好。过高通常会破坏画面。</li><li>多个 LoRA 越多越强。叠加会互相干扰。</li></ul>',25)])])}const p=a(r,[["render",t]]);export{h as __pageData,p as default};
